import PDFDocument from "pdfkit";
import * as XLSX from "xlsx";

type Row = Record<string, unknown>;

const money = (value: unknown) =>
  `Rs. ${Number(value || 0).toLocaleString(
    "en-IN",
    {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    }
  )}`;

const text = (
  value: unknown,
  fallback = "-"
) => {
  const output = String(
    value ?? ""
  ).trim();
  return output || fallback;
};

const dateText = (value: unknown) => {
  if (!value) return "-";
  const date = new Date(String(value));
  return Number.isNaN(date.getTime())
    ? "-"
    : date.toLocaleDateString("en-IN", {
        day: "2-digit",
        month: "short",
        year: "numeric",
      });
};

function collectPdf(
  render: (
    doc: PDFKit.PDFDocument
  ) => void
) {
  return new Promise<Buffer>(
    (resolve, reject) => {
      const doc = new PDFDocument({
        size: "A4",
        margin: 36,
        bufferPages: true,
      });
      const chunks: Buffer[] = [];
      doc.on("data", (chunk) =>
        chunks.push(Buffer.from(chunk))
      );
      doc.on("end", () =>
        resolve(Buffer.concat(chunks))
      );
      doc.on("error", reject);
      render(doc);
      const range =
        doc.bufferedPageRange();
      for (
        let i = range.start;
        i < range.start + range.count;
        i += 1
      ) {
        doc.switchToPage(i);
        doc
          .fontSize(8)
          .fillColor("#6B7280")
          .text(
            `Generated by TOTTECH ONE • Page ${i + 1} of ${range.count}`,
            36,
            805,
            {
              align: "center",
              width: 523,
            }
          );
      }
      doc.end();
    }
  );
}

const columns = [
  ["student_name", "Student"],
  ["admission_number", "Admission No"],
  ["invoice_number", "Invoice"],
  ["receipt_number", "Receipt"],
  ["class_name", "Class"],
  ["section_name", "Section"],
  ["month", "Month"],
  ["status", "Status"],
  ["payment_method", "Payment Method"],
  ["generated", "Generated"],
  ["total_amount", "Total"],
  ["collected", "Collected"],
  ["amount", "Amount"],
  ["pending", "Pending"],
  ["pending_amount", "Pending Amount"],
  ["balance_amount", "Balance"],
  ["concessions", "Concessions"],
  ["approved_amount", "Approved Concession"],
  ["payment_date", "Payment Date"],
  ["invoice_date", "Invoice Date"],
  ["due_date", "Due Date"],
] as const;

function visibleColumns(rows: Row[]) {
  const keys = new Set(
    rows.flatMap((row) =>
      Object.keys(row)
    )
  );
  const selected = columns.filter(
    ([key]) => keys.has(key)
  );
  return selected.length
    ? selected
    : columns.slice(0, 8);
}

export async function renderFinanceReportPdf(
  report: {
    title: string;
    rows: Row[];
    totals: Row;
    context?: {
      selectedSchool?: Row | null;
      selectedAcademicYear?: Row | null;
      all_schools?: boolean;
      all_years?: boolean;
      filters?: Row;
    };
  }
) {
  const rows = report.rows || [];
  const cols = visibleColumns(rows).slice(
    0,
    7
  );

  return collectPdf((doc) => {
    doc
      .fillColor("#04142E")
      .rect(0, 0, 595, 92)
      .fill();
    doc
      .fillColor("#FFFFFF")
      .fontSize(18)
      .font("Helvetica-Bold")
      .text(
        text(
          report.context?.selectedSchool?.school_name,
          report.context?.all_schools
            ? "All Schools"
            : "TOTTECH ONE"
        ),
        36,
        24
      );
    doc
      .fillColor("#D4AF37")
      .fontSize(10)
      .text(report.title, 36, 52);
    doc
      .fillColor("#E5E7EB")
      .fontSize(8)
      .text(
        `Academic Year: ${text(report.context?.selectedAcademicYear?.academic_year, report.context?.all_years ? "All Years" : "-")} • Generated: ${dateText(new Date())}`,
        36,
        70
      );

    const summaryY = 112;
    const summary = [
      ["Generated", report.totals.generated],
      ["Collected", report.totals.collected],
      ["Pending", report.totals.pending],
      ["Concessions", report.totals.concessions],
    ];
    summary.forEach(([label, value], index) => {
      const x = 36 + index * 130;
      doc
        .roundedRect(x, summaryY, 118, 50, 6)
        .strokeColor("#D1D5DB")
        .lineWidth(0.8)
        .stroke();
      doc
        .fillColor("#6B7280")
        .fontSize(8)
        .font("Helvetica-Bold")
        .text(String(label), x + 10, summaryY + 10);
      doc
        .fillColor("#111827")
        .fontSize(11)
        .text(money(value), x + 10, summaryY + 27);
    });

    let y = 190;
    const widths = [78, 74, 72, 64, 64, 70, 84];
    doc
      .fillColor("#F3F4F6")
      .rect(36, y, 523, 24)
      .fill();
    cols.forEach(([, label], index) => {
      doc
        .fillColor("#111827")
        .fontSize(7)
        .font("Helvetica-Bold")
        .text(
          label,
          42 +
            widths
              .slice(0, index)
              .reduce((a, b) => a + b, 0),
          y + 8,
          {
            width: widths[index],
          }
        );
    });
    y += 24;

    rows.slice(0, 120).forEach((row) => {
      if (y > 760) {
        doc.addPage();
        y = 48;
      }
      doc
        .strokeColor("#E5E7EB")
        .moveTo(36, y)
        .lineTo(559, y)
        .stroke();
      cols.forEach(([key], index) => {
        const raw = row[key];
        const value =
          key.includes("amount") ||
          [
            "generated",
            "collected",
            "pending",
            "concessions",
          ].includes(key)
            ? money(raw)
            : key.includes("date")
              ? dateText(raw)
              : text(raw);
        doc
          .fillColor("#111827")
          .fontSize(7)
          .font("Helvetica")
          .text(
            value,
            42 +
              widths
                .slice(0, index)
                .reduce((a, b) => a + b, 0),
            y + 8,
            {
              width: widths[index],
              height: 22,
            }
          );
      });
      y += 34;
    });
  });
}

export function renderFinanceReportXlsx(report: {
  title: string;
  rows: Row[];
  totals: Row;
}) {
  const workbook =
    XLSX.utils.book_new();
  const rows = report.rows || [];
  const jsonRows = rows.map((row) => {
    const output: Record<string, unknown> = {};
    for (const [key, label] of visibleColumns(
      rows
    )) {
      output[label] = row[key] ?? "";
    }
    return output;
  });
  const sheet =
    XLSX.utils.json_to_sheet(jsonRows);
  XLSX.utils.book_append_sheet(
    workbook,
    sheet,
    report.title.slice(0, 31)
  );
  const totalsSheet =
    XLSX.utils.json_to_sheet([
      report.totals,
    ]);
  XLSX.utils.book_append_sheet(
    workbook,
    totalsSheet,
    "Totals"
  );
  return XLSX.write(workbook, {
    type: "buffer",
    bookType: "xlsx",
  }) as Buffer;
}
